// // This is a T-flip-flop with an active low enable signal
module TFF (
    input clk,
    input rst,
    input T,
    output reg Q
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            Q <= 0;
        end else if (T) begin
            Q <= ~Q;
        end
    end
endmodule
